1	import { createHash } from 'crypto';
2	import mongoose from 'mongoose';
3	import { QuestionItem, Test, Subject } from '../models';
4	import { KtpCatalog } from '../models/KtpCatalog.model';
5	import { AppError } from '../utils';
6	import { IKtpCatalog, ICanonicalRoadmapNode } from '../types/roadmap.types';
7	import { IQuestion, IQuestionItem } from '../types';
8	import { buildKtpCanonicalNodes } from '../utils/roadmapKtp.util';
9	import { aiService } from './ai.service';
10	import { knowledgeComponentService } from './knowledgeComponent.service';
11	import { userKcMasteryService } from './userKcMastery.service';
12	import { IUserKcComponentProgress } from '../types';
13	
14	/**
15	 * QUESTION BANK SERVICE (Фаза 2)
16	 * Банк переиспользуемых вопросов, привязанных к узлу знания (ktpTopicId) и KC.
17	 * Генерация — только под ПРОБЕЛ покрытия (а не на каждую попытку); сборка теста = выборка item'ов.
18	 */
19	
20	const BANK_PROMPT_VERSION = 'gpt-4o-mini/bank-v1';
21	const DEFAULT_MIN_ITEMS_PER_KC = 3;
22	const TEST_SIZE = 10; // Test-валидатор требует ровно 10 вопросов
23	
24	function contentHashOf(questionText: string): string {
25	  const norm = questionText.trim().toLowerCase().replace(/\s+/g, ' ');
26	  return createHash('sha256').update(norm).digest('hex');
27	}
28	
29	type ResolvedNode = {
30	  node: ICanonicalRoadmapNode;
31	  nodeTitle: string;
32	  language?: string;
33	  sourceText: string;
34	  sourceRefs: Array<{ bookId?: string; chapterId?: string; topicId?: string }>;
35	  primary: { bookId?: string; chapterId?: string };
36	};
37	
38	class QuestionBankService {
39	  private async assertSubject(subjectId: string): Promise<void> {
40	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
41	  }
42	
43	  /** Разрешить узел КТП: текст источников (для грунтинга) + первичная книга/глава (для Test). */
44	  private async resolveNode(subjectId: string, ktpTopicId: string): Promise<ResolvedNode> {
45	    const subject = await Subject.findById(subjectId).lean();
46	    const ktp = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
47	    if (!subject || !ktp) throw AppError.notFound('Subject or KTP catalog not found');
48	    const nodes = buildKtpCanonicalNodes(subject, ktp);
49	    const node = nodes.find(
50	      (n) => (n.metadata as Record<string, unknown> | undefined)?.ktpTopicId === ktpTopicId
51	    );
52	    if (!node) throw AppError.notFound('KTP node not found or has no sources');
53	
54	    const md = node.metadata as Record<string, unknown>;
55	    const lessons = (md.lessons as Array<{ title?: string; content?: string }> | undefined) ?? [];
56	    const sources = (md.sources as Array<{ bookId: string; chapterId: string; topicId: string }> | undefined) ?? [];
57	    const sourceText = lessons
58	      .map((l) => (l.content || '').trim())
59	      .filter(Boolean)
60	      .join('\n\n');
61	
62	    const primaryBookId = typeof md.bookId === 'string' ? md.bookId : sources[0]?.bookId;
63	    const book = (subject as { books?: Array<{ _id?: { toString(): string }; contentLanguage?: string }> }).books?.find(
64	      (b) => b._id?.toString() === primaryBookId
65	    );
66	
67	    return {
68	      node,
69	      nodeTitle: node.title,
70	      ...(book?.contentLanguage ? { language: book.contentLanguage } : {}),
71	      sourceText,
72	      sourceRefs: sources.map((s) => ({ bookId: s.bookId, chapterId: s.chapterId, topicId: s.topicId })),
73	      primary: {
74	        ...(primaryBookId ? { bookId: primaryBookId } : {}),
75	        ...(typeof md.chapterId === 'string' ? { chapterId: md.chapterId } : {})
76	      }
77	    };
78	  }
79	
80	  /** Покрытие узла: активных item'ов всего и по каждому подтверждённому KC. */
81	  async coverage(
82	    subjectId: string,
83	    ktpTopicId: string
84	  ): Promise<{
85	    totalActive: number;
86	    perKc: Array<{ kcId: string; title: string; active: number }>;
87	    unassigned: number;
88	  }> {
89	    await this.assertSubject(subjectId);
90	    const kcs = await knowledgeComponentService.getConfirmed(subjectId, ktpTopicId);
91	    const active = await QuestionItem.find({ subjectId, knowledgeNodeId: ktpTopicId, status: 'active' })
92	      .select('knowledgeComponentIds')
93	      .lean();
94	    const countByKc = new Map<string, number>();
95	    let unassigned = 0;
96	    for (const it of active) {
97	      const ids = (it.knowledgeComponentIds ?? []) as string[];
98	      if (ids.length === 0) unassigned++;
99	      for (const id of ids) countByKc.set(id, (countByKc.get(id) ?? 0) + 1);
100	    }
101	    return {
102	      totalActive: active.length,
103	      perKc: kcs.map((k) => ({ kcId: k.id, title: k.title, active: countByKc.get(k.id) ?? 0 })),
104	      unassigned
105	    };
106	  }
107	
108	  /**
109	   * Дозаполнить банк под покрытие: для каждого KC с дефицитом активных вопросов
110	   * генерируем недостающие, верифицируем (LLM-judge), дедуплицируем и сохраняем.
111	   * Если подтверждённых KC нет — генерируем на уровне узла (без KC-тега).
112	   */
113	  async generateForCoverage(
114	    subjectId: string,
115	    ktpTopicId: string,
116	    opts?: { minPerKc?: number; difficulty?: number }
117	  ): Promise<{ created: number; rejected: number; coverage: Awaited<ReturnType<QuestionBankService['coverage']>> }> {
118	    await this.assertSubject(subjectId);
119	    const minPerKc = Math.max(1, opts?.minPerKc ?? DEFAULT_MIN_ITEMS_PER_KC);
120	    const difficulty = Math.min(5, Math.max(1, opts?.difficulty ?? 3));
121	
122	    const resolved = await this.resolveNode(subjectId, ktpTopicId);
123	    if (!resolved.sourceText.trim()) throw AppError.badRequest('Node has no source text to ground questions');
124	
125	    const kcs = await knowledgeComponentService.getConfirmed(subjectId, ktpTopicId);
126	    const cov = await this.coverage(subjectId, ktpTopicId);
127	
128	    // Список «целей»: либо по KC с дефицитом, либо одна цель на узел (если KC нет).
129	    const targets: Array<{ kcId?: string; title: string; deficit: number }> = kcs.length
130	      ? cov.perKc
131	          .filter((p) => p.active < minPerKc)
132	          .map((p) => ({ kcId: p.kcId, title: p.title, deficit: minPerKc - p.active }))
133	      : cov.totalActive < minPerKc
134	        ? [{ title: resolved.nodeTitle, deficit: minPerKc - cov.totalActive }]
135	        : [];
136	
137	    let created = 0;
138	    let rejected = 0;
139	    const rejectReasons: string[] = [];
140	
141	    for (const target of targets) {
142	      let generated: IQuestion[];
143	      try {
144	        generated = await aiService.generateKcQuestions({
145	          nodeTitle: resolved.nodeTitle,
146	          kcTitle: target.title,
147	          sourceText: resolved.sourceText,
148	          ...(resolved.language ? { language: resolved.language } : {}),
149	          count: target.deficit,
150	          difficulty
151	        });
152	      } catch (e) {
153	        console.warn('[questionBank] generation failed for', target.title, e);
154	        continue;
155	      }
156	
157	      for (const q of generated) {
158	        // Верификация (анти-галлюцинации).
159	        const verdict = await aiService.verifyQuestionItem({ question: q, sourceText: resolved.sourceText });
160	        if (!verdict.ok) {
161	          rejected++;
162	          if (verdict.reason) rejectReasons.push(verdict.reason);
163	          continue;
164	        }
165	        const hash = contentHashOf(q.questionText);
166	        const doc: Omit<IQuestionItem, '_id' | 'createdAt' | 'updatedAt'> = {
167	          subjectId: new mongoose.Types.ObjectId(subjectId),
168	          knowledgeNodeId: ktpTopicId,
169	          knowledgeComponentIds: target.kcId ? [target.kcId] : [],
170	          question: q,
171	          difficulty,
172	          status: 'active',
173	          sourceRefs: resolved.sourceRefs.map((r) => ({
174	            ...(r.bookId ? { bookId: new mongoose.Types.ObjectId(r.bookId) } : {}),
175	            ...(r.chapterId ? { chapterId: new mongoose.Types.ObjectId(r.chapterId) } : {}),
176	            ...(r.topicId ? { topicId: new mongoose.Types.ObjectId(r.topicId) } : {})
177	          })),
178	          provenance: {
179	            model: 'gpt-4o-mini',
180	            promptVersion: BANK_PROMPT_VERSION,
181	            generatedAt: new Date(),
182	            verified: true,
183	            ...(verdict.reason ? { verifyReason: verdict.reason } : {})
184	          },
185	          contentHash: hash,
186	          qualityStats: { timesUsed: 0, timesCorrect: 0 }
187	        };
188	        try {
189	          await QuestionItem.create(doc);
190	          created++;
191	        } catch (e: unknown) {
192	          // Дубликат (уникальный индекс по contentHash в узле) — молча пропускаем.
193	          if ((e as { code?: number }).code === 11000) continue;
194	          console.warn('[questionBank] insert failed', e);
195	        }
196	      }
197	    }
198	
199	    if (rejectReasons.length) {
200	      console.warn(`[questionBank] отклонено верификатором: ${rejected}. Примеры причин:`);
201	      for (const r of rejectReasons.slice(0, 8)) console.warn('   •', r);
202	    }
203	
204	    const coverageAfter = await this.coverage(subjectId, ktpTopicId);
205	    return { created, rejected, coverage: coverageAfter };
206	  }
207	
208	  /**
209	   * Собрать тест из банка по покрытию KC (round-robin), при нехватке — дозаполнить и пересобрать.
210	   * Возвращает обычный Test-документ (переиспользует существующий submit/grade пайплайн).
211	   */
212	  async assembleNodeTest(
213	    subjectId: string,
214	    ktpTopicId: string,
215	    opts?: { userId?: string }
216	  ): Promise<InstanceType<typeof Test>> {
217	    await this.assertSubject(subjectId);
218	    // Test-валидатор требует ровно 10 вопросов — размер фиксирован.
219	    const size = TEST_SIZE;
220	
221	    // Адаптивный контекст: пер-KC mastery (слабые темы вперёд) + недавние item'ы (SR).
222	    const ctx = opts?.userId
223	      ? {
224	          componentMap: await userKcMasteryService.getComponentMap(opts.userId, subjectId),
225	          recentItems: await userKcMasteryService.getRecentItemIds(opts.userId, subjectId)
226	        }
227	      : undefined;
228	
229	    let items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
230	    if (items.length < size) {
231	      // дозаполняем банк и пробуем ещё раз
232	      await this.generateForCoverage(subjectId, ktpTopicId, { minPerKc: DEFAULT_MIN_ITEMS_PER_KC });
233	      items = await this.selectCovering(subjectId, ktpTopicId, size, ctx);
234	    }
235	    if (items.length < size) {
236	      throw AppError.badRequest(
237	        `Недостаточно вопросов в банке для сборки теста (есть ${items.length} из ${size}). Сгенерируйте больше.`
238	      );
239	    }
240	
241	    const resolved = await this.resolveNode(subjectId, ktpTopicId);
242	    if (!resolved.primary.bookId) throw AppError.badRequest('Node has no primary book to attach test');
243	
244	    const selected = items.slice(0, size);
245	    const sourceContentHash =
246	      'bank:' +
247	      createHash('sha256')
248	        .update(selected.map((i) => String(i._id)).sort().join(','))
249	        .digest('hex');
250	
251	    // Реюз: та же выборка → тот же тест.
252	    const existing = await Test.findOne({ subjectId, sourceContentHash }).sort({ createdAt: -1 });
253	    if (existing) return existing;
254	
255	    const questions: IQuestion[] = selected.map((it) => {
256	      const q = it.question as IQuestion;
257	      return {
258	        ...q,
259	        relatedContent: {
260	          ...q.relatedContent,
261	          ...(resolved.primary.chapterId
262	            ? { chapterId: new mongoose.Types.ObjectId(resolved.primary.chapterId) }
263	            : {})
264	        },
265	        questionItemId: it._id as mongoose.Types.ObjectId,
266	        ...(it.knowledgeComponentIds?.length ? { knowledgeComponentIds: it.knowledgeComponentIds } : {})
267	      };
268	    });
269	
270	    await QuestionItem.updateMany(
271	      { _id: { $in: selected.map((i) => i._id) } },
272	      { $inc: { 'qualityStats.timesUsed': 1 } }
273	    );
274	
275	    return Test.create({
276	      subjectId,
277	      bookId: resolved.primary.bookId,
278	      ...(resolved.primary.chapterId ? { chapterId: resolved.primary.chapterId } : {}),
279	      questions,
280	      sourceContentHash,
281	      testProfile: 'ent'
282	    });
283	  }
284	
285	  /**
286	   * Выбрать активные item'ы, максимизируя покрытие KC (round-robin по KC), до `size`.
287	   * Если задан ctx (пер-KC mastery + недавние item'ы): слабые/неосвоенные KC идут первыми,
288	   * внутри KC — деприоритет недавно показанных (SR) и подбор сложности под уровень освоения.
289	   */
290	  private async selectCovering(
291	    subjectId: string,
292	    ktpTopicId: string,
293	    size: number,
294	    ctx?: { componentMap: Map<string, IUserKcComponentProgress>; recentItems: Set<string> }
295	  ) {
296	    const active = await QuestionItem.find({ subjectId, knowledgeNodeId: ktpTopicId, status: 'active' })
297	      .sort({ 'qualityStats.timesUsed': 1, createdAt: 1 })
298	      .lean();
299	    if (active.length === 0) return [];
300	
301	    // Группируем по KC (item без KC → ключ '_node').
302	    const byKc = new Map<string, typeof active>();
303	    for (const it of active) {
304	      const keys = (it.knowledgeComponentIds ?? []) as string[];
305	      const groupKeys = keys.length ? keys : ['_node'];
306	      for (const k of groupKeys) {
307	        if (!byKc.has(k)) byKc.set(k, []);
308	        byKc.get(k)!.push(it);
309	      }
310	    }
311	
312	    const masteryOf = (kcId: string): number => ctx?.componentMap.get(kcId)?.bestScore ?? 0;
313	    const isRecent = (id: string): boolean => ctx?.recentItems.has(id) ?? false;
314	
315	    // Порядок KC: слабые/неосвоенные первыми (по возрастанию bestScore).
316	    const kcKeys = [...byKc.keys()];
317	    if (ctx) kcKeys.sort((a, b) => masteryOf(a) - masteryOf(b));
318	
319	    // Внутри KC: не показанные недавно — первыми; сложность под уровень (слабому — проще).
320	    for (const k of kcKeys) {
321	      const weak = ctx ? masteryOf(k) < 80 : false;
322	      byKc.get(k)!.sort((x, y) => {
323	        if (ctx) {
324	          const rx = isRecent(String(x._id)) ? 1 : 0;
325	          const ry = isRecent(String(y._id)) ? 1 : 0;
326	          if (rx !== ry) return rx - ry; // не-недавние вперёд
327	          const dx = x.difficulty ?? 3;
328	          const dy = y.difficulty ?? 3;
329	          if (dx !== dy) return weak ? dx - dy : dy - dx; // слабому проще, сильному сложнее
330	        }
331	        return (x.qualityStats?.timesUsed ?? 0) - (y.qualityStats?.timesUsed ?? 0);
332	      });
333	    }
334	
335	    const picked: typeof active = [];
336	    const usedIds = new Set<string>();
337	    let progress = true;
338	    while (picked.length < size && progress) {
339	      progress = false;
340	      for (const k of kcKeys) {
341	        if (picked.length >= size) break;
342	        const pool = byKc.get(k)!;
343	        const next = pool.find((it) => !usedIds.has(String(it._id)));
344	        if (next) {
345	          usedIds.add(String(next._id));
346	          picked.push(next);
347	          progress = true;
348	        }
349	      }
350	    }
351	    return picked;
352	  }
353	}
