1	import type { EntQuestionType, IMatchingItem, IQuestion, IRelatedContent } from '../types';
2	
3	export const ENT_QUESTION_TYPES: EntQuestionType[] = [
4	  'single_choice',
5	  'multiple_choice',
6	  'matching_single',
7	  'matching_multiple',
8	  'short_answer',
9	  'text_input'
10	];
11	
12	export function getQuestionType(q: Partial<IQuestion>): EntQuestionType {
13	  const t = (q as { questionType?: string }).questionType;
14	  if (t && ENT_QUESTION_TYPES.includes(t as EntQuestionType)) return t as EntQuestionType;
15	  return 'single_choice';
16	}
17	
18	export function normText(s: string): string {
19	  return s.trim().toLowerCase().replace(/\s+/g, ' ');
20	}
21	
22	function uniqStrings(arr: string[]): string[] {
23	  const seen = new Set<string>();
24	  const out: string[] = [];
25	  for (const x of arr) {
26	    const k = x.trim();
27	    if (!seen.has(k)) {
28	      seen.add(k);
29	      out.push(x.trim());
30	    }
31	  }
32	  return out;
33	}
34	
35	function setsEqualStrings(a: string[], b: string[]): boolean {
36	  if (a.length !== b.length) return false;
37	  const sa = [...a].map(normText).sort();
38	  const sb = [...b].map(normText).sort();
39	  return sa.every((v, i) => v === sb[i]);
40	}
41	
42	function parseJsonObject(raw: string): Record<string, unknown> | null {
43	  try {
44	    const v = JSON.parse(raw) as unknown;
45	    return v && typeof v === 'object' && !Array.isArray(v) ? (v as Record<string, unknown>) : null;
46	  } catch {
47	    return null;
48	  }
49	}
50	
51	function parseJsonArray(raw: string): unknown[] | null {
52	  try {
53	    const v = JSON.parse(raw) as unknown;
54	    return Array.isArray(v) ? v : null;
55	  } catch {
56	    return null;
57	  }
58	}
59	
60	/** Сводка правильного ответа для UI и AI-разбора */
61	export function formatExpectedAnswer(q: IQuestion): string {
62	  const qt = getQuestionType(q);
63	  switch (qt) {
64	    case 'single_choice':
65	      return q.correctOption ?? '';
66	    case 'multiple_choice':
67	      return (q.correctOptions ?? []).join('; ');
68	    case 'matching_single': {
69	      const cm = q.correctMatching ?? {};
70	      const left = q.matchingLeft ?? [];
71	      const right = q.matchingRight ?? [];
72	      const lines = Object.keys(cm).map((lid) => {
73	        const lt = left.find((x) => x.id === lid)?.text ?? lid;
74	        const rid = cm[lid] as string;
75	        const rt = right.find((x) => x.id === rid)?.text ?? rid;
76	        return `${lt} → ${rt}`;
77	      });
78	      return lines.join(' | ');
79	    }
80	    case 'matching_multiple': {
81	      const cm = q.correctMatching ?? {};
82	      const left = q.matchingLeft ?? [];
83	      const right = q.matchingRight ?? [];
84	      const lines = Object.keys(cm).map((lid) => {
85	        const lt = left.find((x) => x.id === lid)?.text ?? lid;
86	        const rids = cm[lid] as string[];
87	        const rt = (rids || []).map((rid) => right.find((x) => x.id === rid)?.text ?? rid).join(', ');
88	        return `${lt} → [${rt}]`;
89	      });
90	      return lines.join(' | ');
91	    }
92	    case 'short_answer':
93	      return (q.acceptableAnswers ?? []).join(' или ');
94	    case 'text_input':
95	      return (
96	        q.referenceAnswer?.trim() ||
97	        (q.acceptableAnswers ?? []).join(' / ') ||
98	        (q.acceptableKeywords ?? []).join(', ')
99	      );
100	    default:
101	      return '';
102	  }
103	}
104	
105	/**
106	 * Значение для `selectedOption` / состояния ввода на клиенте (как при отправке теста).
107	 * Включать в ответ API только в dev (вместе с correctAnswerHint).
108	 */
109	export function clientPrefillValueForQuestion(q: IQuestion): string {
110	  const qt = getQuestionType(q);
111	  switch (qt) {
112	    case 'single_choice':
113	      return (q.correctOption ?? '').trim();
114	    case 'multiple_choice': {
115	      const co = (q.correctOptions ?? []).filter((x) => String(x).trim());
116	      if (co.length === 0) return '';
117	      return JSON.stringify([...co].map(String).sort());
118	    }
119	    case 'matching_single':
120	    case 'matching_multiple': {
121	      const cm = q.correctMatching;
122	      if (!cm || typeof cm !== 'object') return '';
123	      return JSON.stringify(cm);
124	    }
125	    case 'short_answer': {
126	      const a = (q.acceptableAnswers ?? []).find((x) => String(x).trim());
127	      return a ? String(a).trim() : '';
128	    }
129	    case 'text_input': {
130	      const ref = (q.referenceAnswer ?? '').trim();
131	      if (ref) return ref;
132	      const aa = (q.acceptableAnswers ?? []).find((x) => String(x).trim());
133	      if (aa) return String(aa).trim();
134	      const kw = (q.acceptableKeywords ?? []).find((x) => String(x).trim());
135	      return kw ? String(kw).trim() : '';
136	    }
137	    default:
138	      return (q.correctOption ?? '').trim();
139	  }
140	}
141	
142	/** Кратко показать ответ пользователя в тексте ошибки */
143	export function summarizeUserAnswer(selectedOption: string): string {
144	  const t = selectedOption.trim();
145	  if (!t) return '(пусто)';
146	  if (t.startsWith('{') || t.startsWith('[')) {
147	    try {
148	      const v = JSON.parse(t) as unknown;
149	      if (Array.isArray(v)) return v.join(', ');
150	      if (v && typeof v === 'object') return JSON.stringify(v);
151	    } catch {
152	      /* fallthrough */
153	    }
154	  }
155	  return t.length > 200 ? `${t.slice(0, 200)}…` : t;
156	}
157	
158	export function gradeAnswer(question: IQuestion, selectedOption: string): boolean {
159	  const qt = getQuestionType(question);
160	  const raw = selectedOption.trim();
161	
162	  switch (qt) {
163	    case 'single_choice': {
164	      const co = question.correctOption?.trim() ?? '';
165	      return normText(raw) === normText(co);
166	    }
167	    case 'multiple_choice': {
168	      const arr = parseJsonArray(raw);
169	      if (!arr || !arr.every((x) => typeof x === 'string')) return false;
170	      const user = (arr as string[]).map((x) => x.trim());
171	      const correct = question.correctOptions ?? [];
172	      return setsEqualStrings(user, correct);
173	    }
174	    case 'matching_single': {
175	      const userObj = parseJsonObject(raw);
176	      const correct = question.correctMatching ?? {};
177	      if (!userObj) return false;
178	      const keys = Object.keys(correct);
179	      if (keys.length !== Object.keys(userObj).length) return false;
180	      return keys.every((k) => {
181	        const cv = correct[k];
182	        const uv = userObj[k];
183	        return typeof cv === 'string' && typeof uv === 'string' && normText(cv) === normText(uv);
184	      });
185	    }
186	    case 'matching_multiple': {
187	      const userObj = parseJsonObject(raw);
188	      const correct = question.correctMatching ?? {};
189	      if (!userObj) return false;
190	      const keys = Object.keys(correct);
191	      if (keys.length !== Object.keys(userObj).length) return false;
192	      for (const k of keys) {
193	        const cVal = correct[k];
194	        const uVal = userObj[k];
195	        if (!Array.isArray(cVal) || !Array.isArray(uVal)) return false;
196	        if (!cVal.every((x) => typeof x === 'string') || !uVal.every((x) => typeof x === 'string')) {
197	          return false;
198	        }
199	        if (!setsEqualStrings(cVal as string[], uVal as string[])) return false;
200	      }
201	      return true;
202	    }
203	    case 'short_answer': {
204	      const user = normText(raw);
205	      const ok = question.acceptableAnswers ?? [];
206	      return ok.some((a) => normText(a) === user || user.includes(normText(a)));
207	    }
208	    case 'text_input': {
209	      const user = normText(raw);
210	      if (user.length < 2) return false;
211	      const answers = question.acceptableAnswers ?? [];
212	      if (answers.some((a) => normText(a) === user || user.includes(normText(a)))) return true;
213	      const kws = question.acceptableKeywords ?? [];
214	      if (kws.length > 0) {
215	        const hit = kws.filter((k) => user.includes(normText(k))).length;
216	        return hit >= Math.min(kws.length, Math.max(1, Math.ceil(kws.length * 0.6)));
217	      }
218	      const ref = question.referenceAnswer?.trim();
219	      if (ref) {
220	        const nr = normText(ref);
221	        return user === nr || (nr.length > 4 && (user.includes(nr) || nr.includes(user)));
222	      }
223	      return false;
224	    }
225	    default:
226	      return false;
227	  }
228	}
