523	      }
524	    }
525	
526	    // Генерируем общий вывод
527	    let summary = '';
528	    
529	    if (scorePercent >= 90) {
530	      summary = `Отличная работа! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Вы демонстрируете отличное понимание материала по теме "${contentMetadata.bookTitle}".`;
531	    } else if (scorePercent >= 70) {
532	      summary = `Хороший результат! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Рекомендуем повторить материал по темам, где были допущены ошибки.`;
533	    } else if (scorePercent >= 50) {
